sql:
SELECT league_name, country
FROM leagues
WHERE league_id = 1;

SELECT match_id, league_id, season_id, date, time, home_team_id, away_team_id, home_goals, away_goals, result, attendance, referee
FROM matches
WHERE match_id > 10;

external_knowledge:
- Larger squads: Teams with more than 20 players;
- Notorious player: The player with the most red cards;
- Disciplinary records: Refers to the total number of red cards received by the player.

sql:
SELECT m.season_id, COUNT(*) AS number_of_matches_played
FROM matches m
GROUP BY m.season_id;

SELECT p.player_name
FROM players p
INNER JOIN player_statistics ps ON p.player_id = ps.player_id
WHERE ps.goals_scored = (
    SELECT MAX(goals_scored) FROM player_statistics
);
